patch:
commit 5fabad770f60e144595f935ccb2046479264fdcb
Author: Luís Arteiro <lucho14garfield@gmail.com>
Date:   Tue Feb 24 00:25:52 2026 +0000

    fix> Fix unhandledRejection in Node 20+ in Windows.
---
 src/index.ts | 5 +++++
 1 file changed, 5 insertions(+)

diff --git a/src/index.ts b/src/index.ts
index ca4b6c0..509c8b4 100644
--- a/src/index.ts
+++ b/src/index.ts
@@ -409,6 +409,11 @@ function mockServiceMethod(
         ((typeof result === 'object' && result.then instanceof Function) || result instanceof Readable)
       ) {
         storedResult = result;
+        // Suppress potential unhandledRejection in Node.js v20+ by attaching a no-op catch handler.
+        // The rejection is still forwarded correctly via tryResolveFromStored -> storedResult.then(resolve, reject).
+        if (typeof (storedResult as any).catch === 'function') {
+          (storedResult as Promise<any>).catch(() => {});
+        }
       }
     }
     // Else we call the callback with the value of 'replace'.

commit c962ee2f04dba1693d6d8d3e0d750895e8e48def
Author: Luís Arteiro <lucho14garfield@gmail.com>
Date:   Thu Mar 27 23:55:18 2025 +0000

    fix: Adding args to callback function in `callsFack` method.
---
 src/index.ts | 6 ++----
 1 file changed, 2 insertions(+), 4 deletions(-)

diff --git a/src/index.ts b/src/index.ts
index f7fefbb..ca4b6c0 100644
--- a/src/index.ts
+++ b/src/index.ts
@@ -298,9 +298,7 @@ function mockServiceMethod(
   // Service method mock type guard
   //if (!serviceMethodMock) return;

-  serviceMethodMock.stub = sinon.stub(client, method).callsFake(function () {
-    const args = Array.prototype.slice.call(arguments);
-
+  serviceMethodMock.stub = sinon.stub(client, method).callsFake(function(this: any, ...args: any[]) {
     let userArgs: string | Function[];
     let userCallback: Function;

@@ -417,7 +415,7 @@ function mockServiceMethod(
     else {
       callback(null, replace);
     }
-    return request;
+    return request as any;
   });
 }

